131→   131→		//Note: it is ok for k to be greater than 1, since this might mean
132→   132→		//that an object with a non-zero radius that moved from p0 to p1 
133→   133→		//actually hit the wall on the "other side" of p0.
134→   134→	}
135→   135→
136→   136→	vm_vec_scale2(&d,num,den);
137→   137→
138→   138→	vm_vec_add(new_pnt,p0,&d);
139→   139→
140→   140→	//we should have vm_vec_scale2_add2()
141→   141→
142→   142→	return 1;
