146→   146→typedef struct vec2d {
147→   147→	fix i,j;
148→   148→} vec2d;
149→   149→
150→   150→//given largest componant of normal, return i & j
151→   151→//if largest componant is negative, swap i & j
152→   152→int ij_table[3][2] =        {
153→   153→							{2,1},          //pos x biggest
154→   154→							{0,2},          //pos y biggest
155→   155→							{1,0},          //pos z biggest
156→   156→						};
157→   157→
158→   158→//intersection types
159→   159→#define IT_NONE 0       //doesn't touch face at all
160→   160→#define IT_FACE 1       //touches face
161→   161→#define IT_EDGE 2       //touches edge of face
162→   162→#define IT_POINT        3       //touches vertex
163→   163→
164→   164→//see if a point in inside a face by projecting into 2d
165→   165→uint32_t check_point_to_face(vms_vector *checkp, side *s,int facenum,int nv,int *vertex_list)
166→   166→{
167→   167→	vms_vector_array *checkp_array;
168→   168→	vms_vector_array norm;
169→   169→	vms_vector t;
170→   170→	int biggest;
171→   171→///
172→   172→	int i,j,edge;
173→   173→	uint32_t edgemask;
174→   174→	fix check_i,check_j;
175→   175→	vms_vector_array *v0,*v1;
176→   176→
177→   177→	#ifdef COMPACT_SEGS
178→   178→		get_side_normal(sp, s-sp->sides, facenum, (vms_vector *)&norm );
179→   179→	#else
180→   180→		memcpy( &norm, &s->normals[facenum], sizeof(vms_vector_array));
181→   181→	#endif
182→   182→	checkp_array = (vms_vector_array *)checkp;
183→   183→
184→   184→	//now do 2d check to see if point is in side
185→   185→
186→   186→	//project polygon onto plane by finding largest component of normal
187→   187→	t.x = labs(norm.xyz[0]); t.y = labs(norm.xyz[1]); t.z = labs(norm.xyz[2]);
188→   188→
189→   189→	if (t.x > t.y) if (t.x > t.z) biggest=0; else biggest=2;
190→   190→	else if (t.y > t.z) biggest=1; else biggest=2;
191→   191→
192→   192→	if (norm.xyz[biggest] > 0) {
193→   193→		i = ij_table[biggest][0];
194→   194→		j = ij_table[biggest][1];
195→   195→	}
196→   196→	else {
197→   197→		i = ij_table[biggest][1];
198→   198→		j = ij_table[biggest][0];
199→   199→	}
200→   200→
201→   201→	//now do the 2d problem in the i,j plane
202→   202→
203→   203→	check_i = checkp_array->xyz[i];
204→   204→	check_j = checkp_array->xyz[j];
205→   205→
206→   206→	for (edge=edgemask=0;edge<nv;edge++) 
207→   207→	{
208→   208→		vec2d edgevec,checkvec;
209→   209→		fix d;
210→   210→
211→   211→		v0 = (vms_vector_array *)&Vertices[vertex_list[facenum*3+edge]];
212→   212→		v1 = (vms_vector_array *)&Vertices[vertex_list[facenum*3+((edge+1)%nv)]];
213→   213→
214→   214→		edgevec.i = v1->xyz[i] - v0->xyz[i];
215→   215→		edgevec.j = v1->xyz[j] - v0->xyz[j];
216→   216→
217→   217→		checkvec.i = check_i - v0->xyz[i];
218→   218→		checkvec.j = check_j - v0->xyz[j];
219→   219→
220→   220→		d = fixmul(checkvec.i,edgevec.j) - fixmul(checkvec.j,edgevec.i);
221→   221→
222→   222→		if (d < 0)              		//we are outside of triangle
223→   223→			edgemask |= (1<<edge);
224→   224→	}
225→   225→
226→   226→	return edgemask;
227→   227→
228→   228→}
