230→   230→
231→   231→//check if a sphere intersects a face
232→   232→int check_sphere_to_face(vms_vector *pnt, side *s,int facenum,int nv,fix rad,int *vertex_list)
233→   233→{
234→   234→	vms_vector checkp=*pnt;
235→   235→	uint32_t edgemask;
236→   236→
237→   237→	//now do 2d check to see if point is in side
238→   238→
239→   239→	edgemask = check_point_to_face(pnt,s,facenum,nv,vertex_list);
240→   240→
241→   241→	//we've gone through all the sides, are we inside?
242→   242→
243→   243→	if (edgemask == 0)
244→   244→		return IT_FACE;
245→   245→	else {
246→   246→		vms_vector edgevec,checkvec;            //this time, real 3d vectors
247→   247→		vms_vector closest_point;
248→   248→		fix edgelen,d,dist;
249→   249→		vms_vector *v0,*v1;
250→   250→		int itype;
251→   251→		int edgenum;
252→   252→
253→   253→		//get verts for edge we're behind
254→   254→
255→   255→		for (edgenum=0;!(edgemask&1);(edgemask>>=1),edgenum++);
256→   256→
257→   257→		v0 = &Vertices[vertex_list[facenum*3+edgenum]];
258→   258→		v1 = &Vertices[vertex_list[facenum*3+((edgenum+1)%nv)]];
259→   259→
260→   260→		//check if we are touching an edge or point
261→   261→
262→   262→		vm_vec_sub(&checkvec,&checkp,v0);
263→   263→		edgelen = vm_vec_normalized_dir(&edgevec,v1,v0);
264→   264→		
265→   265→		//find point dist from planes of ends of edge
266→   266→
267→   267→		d = vm_vec_dot(&edgevec,&checkvec);
268→   268→
269→   269→		if (d+rad < 0) return IT_NONE;                  //too far behind start point
270→   270→
271→   271→		if (d-rad > edgelen) return IT_NONE;    //too far part end point
272→   272→
273→   273→		//find closest point on edge to check point
274→   274→
275→   275→		itype = IT_POINT;
276→   276→
277→   277→		if (d < 0) closest_point = *v0;
278→   278→		else if (d > edgelen) closest_point = *v1;
279→   279→		else {
280→   280→			itype = IT_EDGE;
281→   281→
282→   282→			//vm_vec_scale(&edgevec,d);
283→   283→			//vm_vec_add(&closest_point,v0,&edgevec);
284→   284→
285→   285→			vm_vec_scale_add(&closest_point,v0,&edgevec,d);
286→   286→		}
287→   287→
288→   288→		dist = vm_vec_dist(&checkp,&closest_point);
289→   289→
290→   290→		if (dist <= rad)
291→   291→			return (itype==IT_POINT)?IT_NONE:itype;
292→   292→		else
293→   293→			return IT_NONE;
294→   294→	}
295→   295→
296→   296→
297→   297→}
