354→   354→//returns the value of a determinant
355→   355→fix calc_det_value(vms_matrix *det)
356→   356→{
357→   357→	return 	fixmul(det->rvec.x,fixmul(det->uvec.y,det->fvec.z)) -
358→   358→			 	fixmul(det->rvec.x,fixmul(det->uvec.z,det->fvec.y)) -
359→   359→			 	fixmul(det->rvec.y,fixmul(det->uvec.x,det->fvec.z)) +
360→   360→			 	fixmul(det->rvec.y,fixmul(det->uvec.z,det->fvec.x)) +
361→   361→			 	fixmul(det->rvec.z,fixmul(det->uvec.x,det->fvec.y)) -
362→   362→			 	fixmul(det->rvec.z,fixmul(det->uvec.y,det->fvec.x));
363→   363→}
