365→   365→//computes the parameters of closest approach of two lines 
366→   366→//fill in two parameters, t0 & t1.  returns 0 if lines are parallel, else 1
367→   367→int check_line_to_line(fix *t1,fix *t2,vms_vector *p1,vms_vector *v1,vms_vector *p2,vms_vector *v2)
368→   368→{
369→   369→	vms_matrix det;
370→   370→	fix d,cross_mag2;		//mag squared cross product
371→   371→
372→   372→	vm_vec_sub(&det.rvec,p2,p1);
373→   373→	vm_vec_cross(&det.fvec,v1,v2);
374→   374→	cross_mag2 = vm_vec_dot(&det.fvec,&det.fvec);
375→   375→
376→   376→	if (cross_mag2 == 0)
377→   377→		return 0;			//lines are parallel
378→   378→
379→   379→	det.uvec = *v2;
380→   380→	d = calc_det_value(&det);
381→   381→	if (oflow_check(d,cross_mag2))
382→   382→		return 0;
383→   383→	else
384→   384→		*t1 = fixdiv(d,cross_mag2);
385→   385→
386→   386→	det.uvec = *v1;
387→   387→	d = calc_det_value(&det);
388→   388→	if (oflow_check(d,cross_mag2))
389→   389→		return 0;
390→   390→	else
391→   391→		*t2 = fixdiv(d,cross_mag2);
392→   392→
393→   393→	return 1;		//found point
394→   394→}
