406→   406→{
407→   407→	if (disable_new_fvi_stuff)
408→   408→		return check_line_to_face(newp,p0,p1,seg,side,facenum,nv,rad);
409→   409→
410→   410→	if ((seg-Segments)==-1)
411→   411→		Error("segnum == -1 in special_check_line_to_face()");
412→   412→
413→   413→	{
414→   414→	vms_vector move_vec;
415→   415→	fix edge_t,move_t,edge_t2,move_t2,closest_dist;
416→   416→	fix edge_len,move_len;
417→   417→	int vertex_list[6];
418→   418→	int num_faces,edgenum;
419→   419→	uint32_t edgemask;
