432→   432→
433→   433→	if (edgemask == 0)
434→   434→		return check_line_to_face(newp,p0,p1,seg,side,facenum,nv,rad);
435→   435→
436→   436→	for (edgenum=0;!(edgemask&1);edgemask>>=1,edgenum++);
437→   437→
438→   438→	edge_v0 = &Vertices[vertex_list[facenum*3+edgenum]];
439→   439→	edge_v1 = &Vertices[vertex_list[facenum*3+((edgenum+1)%nv)]];
440→   440→
441→   441→	vm_vec_sub(&edge_vec,edge_v1,edge_v0);
442→   442→
443→   443→	//is the start point already touching the edge?
444→   444→
445→   445→	//??
446→   446→
447→   447→	//first, find point of closest approach of vec & edge
448→   448→
449→   449→	edge_len = vm_vec_normalize(&edge_vec);
450→   450→	move_len = vm_vec_normalize(&move_vec);
451→   451→
452→   452→	check_line_to_line(&edge_t,&move_t,edge_v0,&edge_vec,p0,&move_vec);
453→   453→
454→   454→	//make sure t values are in valid range
455→   455→
456→   456→	if (move_t<0 || move_t>move_len+rad)
457→   457→		return IT_NONE;
458→   458→
459→   459→	if (move_t > move_len)
460→   460→		move_t2 = move_len;
461→   461→	else
462→   462→		move_t2 = move_t;
463→   463→
464→   464→	if (edge_t < 0)		//saturate at points
465→   465→		edge_t2 = 0;
466→   466→	else
467→   467→		edge_t2 = edge_t;
468→   468→
469→   469→	if (edge_t2 > edge_len)		//saturate at points
470→   470→		edge_t2 = edge_len;
471→   471→
472→   472→	//now, edge_t & move_t determine closest points.  calculate the points.
473→   473→
474→   474→	vm_vec_scale_add(&closest_point_edge,edge_v0,&edge_vec,edge_t2);
475→   475→	vm_vec_scale_add(&closest_point_move,p0,&move_vec,move_t2);
476→   476→
477→   477→	//find dist between closest points
478→   478→
479→   479→	closest_dist = vm_vec_dist(&closest_point_edge,&closest_point_move);
480→   480→
481→   481→	//could we hit with this dist?
482→   482→
483→   483→	//note massive tolerance here
484→   484→//	if (closest_dist < (rad*18)/20) {		//we hit.  figure out where
485→   485→	if (closest_dist < (rad*15)/20) {		//we hit.  figure out where
486→   486→
487→   487→		//now figure out where we hit
488→   488→
489→   489→		vm_vec_scale_add(newp,p0,&move_vec,move_t-rad);
490→   490→
491→   491→		return IT_EDGE;
492→   492→
493→   493→	}
494→   494→	else
